INSERT INTO "DataItems" VALUES(741,5,'encounter.status_history','List of past encounter statuses','The status history permits the encounter resource to contain the status history without needing to read through the historical versions of the resource, or even have the server store them. (FHIR complex type BackboneElement)','OBJECT',NULL,NULL,0,1,NULL,NULL,NULL,'HL7 FHIR','https://hl7.org/fhir/R4/encounter.html','FHIR R4 (4.0.1)','2026-06-14 20:18:12','2026-06-27 07:45:20');
INSERT INTO "DataItems" VALUES(742,5,'encounter.class','Classification of patient encounter','Concepts representing classification of patient encounter such as ambulatory (outpatient), inpatient, emergency, home health or others due to local variations. (FHIR complex type Coding) (Bound to value set ''v3-ActEncounterCode'' (extensible).)','OBJECT',NULL,NULL,1,0,NULL,NULL,NULL,'HL7 FHIR','https://hl7.org/fhir/R4/encounter.html','FHIR R4 (4.0.1)','2026-06-14 20:18:12','2026-06-27 07:45:20');
INSERT INTO "DataItems" VALUES(743,5,'encounter.class_history','List of past encounter classes','The class history permits the tracking of the encounters transitions without needing to go  through the resource history.  This would be used for a case where an admission starts of as an emergency encounter, then transitions into an inpatient scenario. Doing this and not restarting a new encounter ensures that any lab/diagnostic results can more easily follow the patient and not require re-processing and not get lost or cancelled during a kind of discharge from emergency to inpatient. (FHIR complex type BackboneElement)','OBJECT',NULL,NULL,0,1,NULL,NULL,NULL,'HL7 FHIR','https://hl7.org/fhir/R4/encounter.html','FHIR R4 (4.0.1)','2026-06-14 20:18:12','2026-06-27 07:45:20');
INSERT INTO "DataItems" VALUES(744,5,'encounter.type','Specific type of encounter','Specific type of encounter (e.g. e-mail consultation, surgical day-care, skilled nursing, rehabilitation). (FHIR complex type CodeableConcept)','OBJECT',NULL,NULL,0,1,NULL,NULL,NULL,'HL7 FHIR','https://hl7.org/fhir/R4/encounter.html','FHIR R4 (4.0.1)','2026-06-14 20:18:12','2026-06-27 07:45:20');
INSERT INTO "DataItems" VALUES(745,5,'encounter.service_type','Specific type of service','Broad categorization of the service that is to be provided (e.g. cardiology). (FHIR complex type CodeableConcept)','OBJECT',NULL,NULL,0,1,NULL,NULL,NULL,'HL7 FHIR','https://hl7.org/fhir/R4/encounter.html','FHIR R4 (4.0.1)','2026-06-14 20:18:12','2026-06-27 07:45:20');
INSERT INTO "DataItems" VALUES(746,5,'encounter.priority','Indicates the urgency of the encounter','Indicates the urgency of the encounter. (FHIR complex type CodeableConcept)','OBJECT',NULL,NULL,0,1,NULL,NULL,NULL,'HL7 FHIR','https://hl7.org/fhir/R4/encounter.html','FHIR R4 (4.0.1)','2026-06-14 20:18:12','2026-06-27 07:45:20');
INSERT INTO "DataItems" VALUES(747,5,'encounter.subject','The patient or group present at the encounter','The patient or group present at the encounter. (references Group, Patient)','RELATION',NULL,NULL,0,1,NULL,NULL,NULL,'HL7 FHIR','https://hl7.org/fhir/R4/encounter.html','FHIR R4 (4.0.1)','2026-06-14 20:18:12','2026-06-27 07:45:20');
INSERT INTO "DataItems" VALUES(748,5,'encounter.episode_of_care','Episode(s) of care that this encounter should be recorded against','Where a specific encounter should be classified as a part of a specific episode(s) of care this field should be used. This association can facilitate grouping of related encounters together for a specific purpose, such as government reporting, issue tracking, association via a common problem.  The association is recorded on the encounter as these are typically created after the episode of care and grouped on entry rather than editing the episode of care to append another encounter to it (the episode of care could span years). (references EpisodeOfCare)','RELATION',NULL,NULL,0,1,NULL,NULL,NULL,'HL7 FHIR','https://hl7.org/fhir/R4/encounter.html','FHIR R4 (4.0.1)','2026-06-14 20:18:12','2026-06-27 07:45:20');
INSERT INTO "DataItems" VALUES(749,5,'encounter.based_on','The ServiceRequest that initiated this encounter','The request this encounter satisfies (e.g. incoming referral or procedure request). (references ServiceRequest)','RELATION',NULL,NULL,0,1,NULL,NULL,NULL,'HL7 FHIR','https://hl7.org/fhir/R4/encounter.html','FHIR R4 (4.0.1)','2026-06-14 20:18:12','2026-06-27 07:45:20');
INSERT INTO "DataItems" VALUES(750,5,'encounter.participant','List of participants involved in the encounter','The list of people responsible for providing the service. (FHIR complex type BackboneElement)','OBJECT',NULL,NULL,0,1,NULL,NULL,NULL,'HL7 FHIR','https://hl7.org/fhir/R4/encounter.html','FHIR R4 (4.0.1)','2026-06-14 20:18:12','2026-06-27 07:45:20');
INSERT INTO "DataItems" VALUES(751,5,'encounter.appointment','The appointment that scheduled this encounter','The appointment that scheduled this encounter. (references Appointment)','RELATION',NULL,NULL,0,1,NULL,NULL,NULL,'HL7 FHIR','https://hl7.org/fhir/R4/encounter.html','FHIR R4 (4.0.1)','2026-06-14 20:18:12','2026-06-27 07:45:20');
INSERT INTO "DataItems" VALUES(752,5,'encounter.period','The start and end time of the encounter','The start and end time of the encounter. (FHIR complex type Period)','OBJECT',NULL,NULL,0,1,NULL,NULL,NULL,'HL7 FHIR','https://hl7.org/fhir/R4/encounter.html','FHIR R4 (4.0.1)','2026-06-14 20:18:12','2026-06-27 07:45:20');
INSERT INTO "DataItems" VALUES(753,5,'encounter.length','Quantity of time the encounter lasted (less time absent)','Quantity of time the encounter lasted. This excludes the time during leaves of absence. (FHIR complex type Duration)','OBJECT',NULL,NULL,0,1,NULL,NULL,NULL,'HL7 FHIR','https://hl7.org/fhir/R4/encounter.html','FHIR R4 (4.0.1)','2026-06-14 20:18:12','2026-06-27 07:45:20');
INSERT INTO "DataItems" VALUES(754,5,'encounter.reason_code','Coded reason the encounter takes place','Reason the encounter takes place, expressed as a code. For admissions, this can be used for a coded admission diagnosis. (FHIR complex type CodeableConcept)','OBJECT',NULL,NULL,0,1,NULL,NULL,NULL,'HL7 FHIR','https://hl7.org/fhir/R4/encounter.html','FHIR R4 (4.0.1)','2026-06-14 20:18:12','2026-06-27 07:45:20');
INSERT INTO "DataItems" VALUES(755,5,'encounter.reason_reference','Reason the encounter takes place (reference)','Reason the encounter takes place, expressed as a code. For admissions, this can be used for a coded admission diagnosis. (references Condition, ImmunizationRecommendation, Observation, Procedure)','RELATION',NULL,NULL,0,1,NULL,NULL,NULL,'HL7 FHIR','https://hl7.org/fhir/R4/encounter.html','FHIR R4 (4.0.1)','2026-06-14 20:18:12','2026-06-27 07:45:20');
INSERT INTO "DataItems" VALUES(756,5,'encounter.diagnosis','The list of diagnosis relevant to this encounter','The list of diagnosis relevant to this encounter. (FHIR complex type BackboneElement)','OBJECT',NULL,NULL,0,1,NULL,NULL,NULL,'HL7 FHIR','https://hl7.org/fhir/R4/encounter.html','FHIR R4 (4.0.1)','2026-06-14 20:18:12','2026-06-27 07:45:20');
INSERT INTO "DataItems" VALUES(757,5,'encounter.account','The set of accounts that may be used for billing for this Encounter','The set of accounts that may be used for billing for this Encounter. (references Account)','RELATION',NULL,NULL,0,1,NULL,NULL,NULL,'HL7 FHIR','https://hl7.org/fhir/R4/encounter.html','FHIR R4 (4.0.1)','2026-06-14 20:18:12','2026-06-27 07:45:20');
INSERT INTO "DataItems" VALUES(758,5,'encounter.hospitalization','Details about the admission to a healthcare service','Details about the admission to a healthcare service. (FHIR complex type BackboneElement)','OBJECT',NULL,NULL,0,1,NULL,NULL,NULL,'HL7 FHIR','https://hl7.org/fhir/R4/encounter.html','FHIR R4 (4.0.1)','2026-06-14 20:18:12','2026-06-27 07:45:20');
INSERT INTO "DataItems" VALUES(759,5,'encounter.location','List of locations where the patient has been','List of locations where  the patient has been during this encounter. (FHIR complex type BackboneElement)','OBJECT',NULL,NULL,0,1,NULL,NULL,NULL,'HL7 FHIR','https://hl7.org/fhir/R4/encounter.html','FHIR R4 (4.0.1)','2026-06-14 20:18:12','2026-06-27 07:45:20');
INSERT INTO "DataItems" VALUES(760,5,'encounter.service_provider','The organization (facility) responsible for this encounter','The organization that is primarily responsible for this Encounter''s services. This MAY be the same as the organization on the Patient record, however it could be different, such as if the actor performing the services was from an external organization (which may be billed seperately) for an external consultation.  Refer to the example bundle showing an abbreviated set of Encounters for a colonoscopy. (references Organization)','RELATION',NULL,NULL,0,1,NULL,NULL,NULL,'HL7 FHIR','https://hl7.org/fhir/R4/encounter.html','FHIR R4 (4.0.1)','2026-06-14 20:18:12','2026-06-27 07:45:20');
INSERT INTO "DataItems" VALUES(761,5,'encounter.part_of','Another Encounter this encounter is part of','Another Encounter of which this encounter is a part of (administratively or in time). (references Encounter)','RELATION',NULL,NULL,0,1,NULL,NULL,NULL,'HL7 FHIR','https://hl7.org/fhir/R4/encounter.html','FHIR R4 (4.0.1)','2026-06-14 20:18:12','2026-06-27 07:45:20');
INSERT INTO "DataItems" VALUES(762,5,'observation.identifier','Business Identifier for observation','A unique identifier assigned to this observation. (FHIR complex type Identifier)','OBJECT',NULL,NULL,0,1,NULL,NULL,NULL,'HL7 FHIR','https://hl7.org/fhir/R4/observation.html','FHIR R4 (4.0.1)','2026-06-14 20:18:12','2026-06-27 07:45:20');
INSERT INTO "DataItems" VALUES(763,5,'observation.based_on','Fulfills plan, proposal or order','A plan, proposal or order that is fulfilled in whole or in part by this event.  For example, a MedicationRequest may require a patient to have laboratory test performed before  it is dispensed. (references CarePlan, DeviceRequest, ImmunizationRecommendation, MedicationRequest, NutritionOrder, ServiceRequest)','RELATION',NULL,NULL,0,1,NULL,NULL,NULL,'HL7 FHIR','https://hl7.org/fhir/R4/observation.html','FHIR R4 (4.0.1)','2026-06-14 20:18:12','2026-06-27 07:45:20');
INSERT INTO "DataItems" VALUES(764,5,'observation.part_of','Part of referenced event','A larger event of which this particular Observation is a component or step.  For example,  an observation as part of a procedure. (references ImagingStudy, Immunization, MedicationAdministration, MedicationDispense, MedicationStatement, Procedure)','RELATION',NULL,NULL,0,1,NULL,NULL,NULL,'HL7 FHIR','https://hl7.org/fhir/R4/observation.html','FHIR R4 (4.0.1)','2026-06-14 20:18:12','2026-06-27 07:45:20');
INSERT INTO "DataItems" VALUES(765,5,'observation.status','registered | preliminary | final | amended +','The status of the result value. (Bound to value set ''observation-status'' (required).)','VARCHAR',NULL,NULL,1,0,NULL,NULL,NULL,'HL7 FHIR','https://hl7.org/fhir/R4/observation.html','FHIR R4 (4.0.1)','2026-06-14 20:18:12','2026-06-27 07:45:20');
INSERT INTO "DataItems" VALUES(766,5,'observation.category','Classification of  type of observation','A code that classifies the general type of observation being made. (FHIR complex type CodeableConcept)','OBJECT',NULL,NULL,0,1,NULL,NULL,NULL,'HL7 FHIR','https://hl7.org/fhir/R4/observation.html','FHIR R4 (4.0.1)','2026-06-14 20:18:12','2026-06-27 07:45:20');
INSERT INTO "DataItems" VALUES(767,5,'observation.code','Type of observation (code / type)','Describes what was observed. Sometimes this is called the observation "name". (FHIR complex type CodeableConcept)','OBJECT',NULL,NULL,1,0,NULL,NULL,NULL,'HL7 FHIR','https://hl7.org/fhir/R4/observation.html','FHIR R4 (4.0.1)','2026-06-14 20:18:12','2026-06-27 07:45:20');
INSERT INTO "DataItems" VALUES(768,5,'observation.subject','Who and/or what the observation is about','The patient, or group of patients, location, or device this observation is about and into whose record the observation is placed. If the actual focus of the observation is different from the subject (or a sample of, part, or region of the subject), the `focus` element or the `code` itself specifies the actual focus of the observation. (references Device, Group, Location, Patient)','RELATION',NULL,NULL,0,1,NULL,NULL,NULL,'HL7 FHIR','https://hl7.org/fhir/R4/observation.html','FHIR R4 (4.0.1)','2026-06-14 20:18:12','2026-06-27 07:45:20');
INSERT INTO "DataItems" VALUES(769,5,'observation.focus','What the observation is about, when it is not about the subject of record','The actual focus of an observation when it is not the patient of record representing something or someone associated with the patient such as a spouse, parent, fetus, or donor. For example, fetus observations in a mother''s record.  The focus of an observation could also be an existing condition,  an intervention, the subject''s diet,  another observation of the subject,  or a body structure such as tumor or implanted device.   An example use case would be using the Observation resource to capture whether the mother is trained to change her child''s tracheostomy tube. In this example, the child is the patient of record and the mother is the focus. (references Resource)','RELATION',NULL,NULL,0,1,NULL,NULL,NULL,'HL7 FHIR','https://hl7.org/fhir/R4/observation.html','FHIR R4 (4.0.1)','2026-06-14 20:18:12','2026-06-27 07:45:20');
INSERT INTO "DataItems" VALUES(770,5,'observation.encounter','Healthcare event during which this observation is made','The healthcare event  (e.g. a patient and healthcare provider interaction) during which this observation is made. (references Encounter)','RELATION',NULL,NULL,0,1,NULL,NULL,NULL,'HL7 FHIR','https://hl7.org/fhir/R4/observation.html','FHIR R4 (4.0.1)','2026-06-14 20:18:12','2026-06-27 07:45:20');
INSERT INTO "DataItems" VALUES(771,5,'observation.effective[x]','Clinically relevant time/time-period for observation','The time or time-period the observed value is asserted as being true. For biological subjects - e.g. human patients - this is usually called the "physiologically relevant time". This is usually either the time of the procedure or of specimen collection, but very often the source of the date/time is not known, only the date/time itself.','DATETIME',NULL,NULL,0,1,NULL,NULL,NULL,'HL7 FHIR','https://hl7.org/fhir/R4/observation.html','FHIR R4 (4.0.1)','2026-06-14 20:18:12','2026-06-27 07:45:20');
INSERT INTO "DataItems" VALUES(772,5,'observation.issued','Date/Time this version was made available','The date and time this version of the observation was made available to providers, typically after the results have been reviewed and verified.','DATETIME',NULL,NULL,0,1,NULL,NULL,NULL,'HL7 FHIR','https://hl7.org/fhir/R4/observation.html','FHIR R4 (4.0.1)','2026-06-14 20:18:12','2026-06-27 07:45:20');
INSERT INTO "DataItems" VALUES(773,5,'observation.performer','Who is responsible for the observation','Who was responsible for asserting the observed value as "true". (references CareTeam, Organization, Patient, Practitioner, PractitionerRole, RelatedPerson)','RELATION',NULL,NULL,0,1,NULL,NULL,NULL,'HL7 FHIR','https://hl7.org/fhir/R4/observation.html','FHIR R4 (4.0.1)','2026-06-14 20:18:12','2026-06-27 07:45:20');
INSERT INTO "DataItems" VALUES(774,5,'observation.value[x]','Actual result','The information determined as a result of making the observation, if the information has a simple value. (FHIR complex type Quantity)','OBJECT',NULL,NULL,0,1,NULL,NULL,NULL,'HL7 FHIR','https://hl7.org/fhir/R4/observation.html','FHIR R4 (4.0.1)','2026-06-14 20:18:12','2026-06-27 07:45:20');
INSERT INTO "DataItems" VALUES(775,5,'observation.data_absent_reason','Why the result is missing','Provides a reason why the expected value in the element Observation.value[x] is missing. (FHIR complex type CodeableConcept) (Bound to value set ''data-absent-reason'' (extensible).)','OBJECT',NULL,NULL,0,1,NULL,NULL,NULL,'HL7 FHIR','https://hl7.org/fhir/R4/observation.html','FHIR R4 (4.0.1)','2026-06-14 20:18:12','2026-06-27 07:45:20');
INSERT INTO "DataItems" VALUES(776,5,'observation.interpretation','High, low, normal, etc.','A categorical assessment of an observation value.  For example, high, low, normal. (FHIR complex type CodeableConcept) (Bound to value set ''observation-interpretation'' (extensible).)','OBJECT',NULL,NULL,0,1,NULL,NULL,NULL,'HL7 FHIR','https://hl7.org/fhir/R4/observation.html','FHIR R4 (4.0.1)','2026-06-14 20:18:12','2026-06-27 07:45:20');
INSERT INTO "DataItems" VALUES(777,5,'observation.note','Comments about the observation','Comments about the observation or the results. (FHIR complex type Annotation)','OBJECT',NULL,NULL,0,1,NULL,NULL,NULL,'HL7 FHIR','https://hl7.org/fhir/R4/observation.html','FHIR R4 (4.0.1)','2026-06-14 20:18:12','2026-06-27 07:45:20');
INSERT INTO "DataItems" VALUES(778,5,'observation.body_site','Observed body part','Indicates the site on the subject''s body where the observation was made (i.e. the target site). (FHIR complex type CodeableConcept)','OBJECT',NULL,NULL,0,1,NULL,NULL,NULL,'HL7 FHIR','https://hl7.org/fhir/R4/observation.html','FHIR R4 (4.0.1)','2026-06-14 20:18:12','2026-06-27 07:45:20');
INSERT INTO "DataItems" VALUES(779,5,'observation.method','How it was done','Indicates the mechanism used to perform the observation. (FHIR complex type CodeableConcept)','OBJECT',NULL,NULL,0,1,NULL,NULL,NULL,'HL7 FHIR','https://hl7.org/fhir/R4/observation.html','FHIR R4 (4.0.1)','2026-06-14 20:18:12','2026-06-27 07:45:20');
INSERT INTO "DataItems" VALUES(780,5,'observation.specimen','Specimen used for this observation','The specimen that was used when this observation was made. (references Specimen)','RELATION',NULL,NULL,0,1,NULL,NULL,NULL,'HL7 FHIR','https://hl7.org/fhir/R4/observation.html','FHIR R4 (4.0.1)','2026-06-14 20:18:12','2026-06-27 07:45:20');
INSERT INTO "DataItems" VALUES(781,5,'observation.device','(Measurement) Device','The device used to generate the observation data. (references Device, DeviceMetric)','RELATION',NULL,NULL,0,1,NULL,NULL,NULL,'HL7 FHIR','https://hl7.org/fhir/R4/observation.html','FHIR R4 (4.0.1)','2026-06-14 20:18:12','2026-06-27 07:45:20');
INSERT INTO "DataItems" VALUES(782,5,'observation.reference_range','Provides guide for interpretation','Guidance on how to interpret the value by comparison to a normal or recommended range.  Multiple reference ranges are interpreted as an "OR".   In other words, to represent two distinct target populations, two `referenceRange` elements would be used. (FHIR complex type BackboneElement)','OBJECT',NULL,NULL,0,1,NULL,NULL,NULL,'HL7 FHIR','https://hl7.org/fhir/R4/observation.html','FHIR R4 (4.0.1)','2026-06-14 20:18:12','2026-06-27 07:45:20');
INSERT INTO "DataItems" VALUES(783,5,'observation.has_member','Related resource that belongs to the Observation group','This observation is a group observation (e.g. a battery, a panel of tests, a set of vital sign measurements) that includes the target as a member of the group. (references MolecularSequence, Observation, QuestionnaireResponse)','RELATION',NULL,NULL,0,1,NULL,NULL,NULL,'HL7 FHIR','https://hl7.org/fhir/R4/observation.html','FHIR R4 (4.0.1)','2026-06-14 20:18:12','2026-06-27 07:45:20');
INSERT INTO "DataItems" VALUES(784,5,'observation.derived_from','Related measurements the observation is made from','The target resource that represents a measurement from which this observation value is derived. For example, a calculated anion gap or a fetal measurement based on an ultrasound image. (references DocumentReference, ImagingStudy, Media, MolecularSequence, Observation, QuestionnaireResponse)','RELATION',NULL,NULL,0,1,NULL,NULL,NULL,'HL7 FHIR','https://hl7.org/fhir/R4/observation.html','FHIR R4 (4.0.1)','2026-06-14 20:18:12','2026-06-27 07:45:20');
INSERT INTO "DataItems" VALUES(785,5,'observation.component','Component results','Some observations have multiple component observations.  These component observations are expressed as separate code value pairs that share the same attributes.  Examples include systolic and diastolic component observations for blood pressure measurement and multiple component observations for genetics observations. (FHIR complex type BackboneElement)','OBJECT',NULL,NULL,0,1,NULL,NULL,NULL,'HL7 FHIR','https://hl7.org/fhir/R4/observation.html','FHIR R4 (4.0.1)','2026-06-14 20:18:12','2026-06-27 07:45:20');
INSERT INTO "DataItems" VALUES(786,5,'coverage.identifier','Business Identifier for the coverage','A unique identifier assigned to this coverage. (FHIR complex type Identifier)','OBJECT',NULL,NULL,0,1,NULL,NULL,NULL,'HL7 FHIR','https://hl7.org/fhir/R4/coverage.html','FHIR R4 (4.0.1)','2026-06-14 20:18:12','2026-06-27 07:45:20');
INSERT INTO "DataItems" VALUES(787,5,'coverage.status','active | cancelled | draft | entered-in-error','The status of the resource instance. (Bound to value set ''fm-status'' (required).)','VARCHAR',NULL,NULL,1,0,NULL,NULL,NULL,'HL7 FHIR','https://hl7.org/fhir/R4/coverage.html','FHIR R4 (4.0.1)','2026-06-14 20:18:12','2026-06-27 07:45:20');
INSERT INTO "DataItems" VALUES(788,5,'coverage.type','Coverage category such as medical or accident','The type of coverage: social program, medical plan, accident coverage (workers compensation, auto), group health or payment by an individual or organization. (FHIR complex type CodeableConcept)','OBJECT',NULL,NULL,0,1,NULL,NULL,NULL,'HL7 FHIR','https://hl7.org/fhir/R4/coverage.html','FHIR R4 (4.0.1)','2026-06-14 20:18:12','2026-06-27 07:45:20');
INSERT INTO "DataItems" VALUES(789,5,'coverage.policy_holder','Owner of the policy','The party who ''owns'' the insurance policy. (references Organization, Patient, RelatedPerson)','RELATION',NULL,NULL,0,1,NULL,NULL,NULL,'HL7 FHIR','https://hl7.org/fhir/R4/coverage.html','FHIR R4 (4.0.1)','2026-06-14 20:18:12','2026-06-27 07:45:20');
INSERT INTO "DataItems" VALUES(790,5,'coverage.subscriber','Subscriber to the policy','The party who has signed-up for or ''owns'' the contractual relationship to the policy or to whom the benefit of the policy for services rendered to them or their family is due. (references Patient, RelatedPerson)','RELATION',NULL,NULL,0,1,NULL,NULL,NULL,'HL7 FHIR','https://hl7.org/fhir/R4/coverage.html','FHIR R4 (4.0.1)','2026-06-14 20:18:12','2026-06-27 07:45:20');
INSERT INTO "DataItems" VALUES(791,5,'coverage.subscriber_id','ID assigned to the subscriber','The insurer assigned ID for the Subscriber.','VARCHAR',NULL,NULL,0,1,NULL,NULL,NULL,'HL7 FHIR','https://hl7.org/fhir/R4/coverage.html','FHIR R4 (4.0.1)','2026-06-14 20:18:12','2026-06-27 07:45:20');
INSERT INTO "DataItems" VALUES(792,5,'coverage.beneficiary','Plan beneficiary','The party who benefits from the insurance coverage; the patient when products and/or services are provided. (references Patient)','RELATION',NULL,NULL,1,0,NULL,NULL,NULL,'HL7 FHIR','https://hl7.org/fhir/R4/coverage.html','FHIR R4 (4.0.1)','2026-06-14 20:18:12','2026-06-27 07:45:20');
INSERT INTO "DataItems" VALUES(793,5,'coverage.dependent','Dependent number','A unique identifier for a dependent under the coverage.','VARCHAR',NULL,NULL,0,1,NULL,NULL,NULL,'HL7 FHIR','https://hl7.org/fhir/R4/coverage.html','FHIR R4 (4.0.1)','2026-06-14 20:18:12','2026-06-27 07:45:20');
INSERT INTO "DataItems" VALUES(794,5,'coverage.relationship','Beneficiary relationship to the subscriber','The relationship of beneficiary (patient) to the subscriber. (FHIR complex type CodeableConcept) (Bound to value set ''subscriber-relationship'' (extensible).)','OBJECT',NULL,NULL,0,1,NULL,NULL,NULL,'HL7 FHIR','https://hl7.org/fhir/R4/coverage.html','FHIR R4 (4.0.1)','2026-06-14 20:18:12','2026-06-27 07:45:20');
INSERT INTO "DataItems" VALUES(795,5,'coverage.period','Coverage start and end dates','Time period during which the coverage is in force. A missing start date indicates the start date isn''t known, a missing end date means the coverage is continuing to be in force. (FHIR complex type Period)','OBJECT',NULL,NULL,0,1,NULL,NULL,NULL,'HL7 FHIR','https://hl7.org/fhir/R4/coverage.html','FHIR R4 (4.0.1)','2026-06-14 20:18:12','2026-06-27 07:45:20');
INSERT INTO "DataItems" VALUES(796,5,'coverage.payor','Issuer of the policy','The program or plan underwriter or payor including both insurance and non-insurance agreements, such as patient-pay agreements. (references Organization, Patient, RelatedPerson)','RELATION',NULL,NULL,1,0,NULL,NULL,NULL,'HL7 FHIR','https://hl7.org/fhir/R4/coverage.html','FHIR R4 (4.0.1)','2026-06-14 20:18:12','2026-06-27 07:45:20');
INSERT INTO "DataItems" VALUES(797,5,'coverage.class','Additional coverage classifications','A suite of underwriter specific classifiers. (FHIR complex type BackboneElement)','OBJECT',NULL,NULL,0,1,NULL,NULL,NULL,'HL7 FHIR','https://hl7.org/fhir/R4/coverage.html','FHIR R4 (4.0.1)','2026-06-14 20:18:12','2026-06-27 07:45:20');
INSERT INTO "DataItems" VALUES(798,5,'coverage.order','Relative order of the coverage','The order of applicability of this coverage relative to other coverages which are currently in force. Note, there may be gaps in the numbering and this does not imply primary, secondary etc. as the specific positioning of coverages depends upon the episode of care.','INTEGER',NULL,NULL,0,1,NULL,NULL,NULL,'HL7 FHIR','https://hl7.org/fhir/R4/coverage.html','FHIR R4 (4.0.1)','2026-06-14 20:18:12','2026-06-27 07:45:20');
INSERT INTO "DataItems" VALUES(799,5,'coverage.network','Insurer network','The insurer-specific identifier for the insurer-defined network of providers to which the beneficiary may seek treatment which will be covered at the ''in-network'' rate, otherwise ''out of network'' terms and conditions apply.','VARCHAR',NULL,NULL,0,1,NULL,NULL,NULL,'HL7 FHIR','https://hl7.org/fhir/R4/coverage.html','FHIR R4 (4.0.1)','2026-06-14 20:18:12','2026-06-27 07:45:20');
INSERT INTO "DataItems" VALUES(800,5,'coverage.cost_to_beneficiary','Patient payments for services/products','A suite of codes indicating the cost category and associated amount which have been detailed in the policy and may have been  included on the health card. (FHIR complex type BackboneElement)','OBJECT',NULL,NULL,0,1,NULL,NULL,NULL,'HL7 FHIR','https://hl7.org/fhir/R4/coverage.html','FHIR R4 (4.0.1)','2026-06-14 20:18:12','2026-06-27 07:45:20');
INSERT INTO "DataItems" VALUES(801,5,'coverage.subrogation','Reimbursement to insurer','When ''subrogation=true'' this insurance instance has been included not for adjudication but to provide insurers with the details to recover costs.','BOOLEAN',NULL,NULL,0,1,NULL,NULL,NULL,'HL7 FHIR','https://hl7.org/fhir/R4/coverage.html','FHIR R4 (4.0.1)','2026-06-14 20:18:12','2026-06-27 07:45:20');
