INSERT INTO "DataItems" VALUES(803,1,'organization.identifier','Identifies this organization  across multiple systems','The identifier property represents any kind of identifier for any kind of [[Thing]], such as ISBNs, GTIN codes, UUIDs etc. Schema.org provides dedicated properties for representing many of these, either as textual strings or as URL (URI) links. See [background notes](/docs/datamodel.html#identifierBg) for more details.','OBJECT',NULL,NULL,0,1,NULL,NULL,NULL,'HL7 FHIR; Schema.org','https://hl7.org/fhir/R4/organization.html | https://schema.org/identifier','FHIR R4 (4.0.1); schemaorg-current-https','2026-06-14 20:18:12','2026-06-27 07:45:20');
INSERT INTO "DataItems" VALUES(804,1,'organization.active','Whether the organization''s record is still in active use','Whether the organization''s record is still in active use.','BOOLEAN',NULL,NULL,0,1,NULL,NULL,NULL,'HL7 FHIR','https://hl7.org/fhir/R4/organization.html','FHIR R4 (4.0.1)','2026-06-14 20:18:12','2026-06-27 07:45:20');
