INSERT INTO "DataItems" VALUES(1764,1,'customer.address','address','The customer''s address.','RELATION',NULL,NULL,0,1,NULL,NULL,NULL,'Stripe API','https://github.com/stripe/openapi/blob/master/openapi/spec3.json','stripe/openapi spec3','2026-06-14 20:18:12','2026-06-27 07:45:20');
INSERT INTO "DataItems" VALUES(1765,1,'customer.balance','balance','The current balance, if any, that''s stored on the customer in their default currency. If negative, the customer has credit to apply to their next invoice. If positive, the customer has an amount owed that''s added to their next invoice. The balance only considers amounts that Stripe hasn''t successfully applied to any invoice. It doesn''t reflect unpaid invoices. This balance is only taken into account after invoices finalize. For multi-currency balances, see [invoice_credit_balance](https://docs.stripe.com/api/customers/object#customer_object-invoice_credit_balance).','INTEGER',NULL,NULL,0,1,NULL,NULL,NULL,'Stripe API','https://github.com/stripe/openapi/blob/master/openapi/spec3.json','stripe/openapi spec3','2026-06-14 20:18:12','2026-06-27 07:45:20');
INSERT INTO "DataItems" VALUES(1766,1,'customer.business_name','business_name','The customer''s business name.','VARCHAR',150,NULL,0,1,NULL,NULL,NULL,'Stripe API','https://github.com/stripe/openapi/blob/master/openapi/spec3.json','stripe/openapi spec3','2026-06-14 20:18:12','2026-06-27 07:45:20');
INSERT INTO "DataItems" VALUES(1767,1,'customer.cash_balance','cash_balance','The current funds being held by Stripe on behalf of the customer. You can apply these funds towards payment intents when the source is "cash_balance". The `settings[reconciliation_mode]` field describes if these funds apply to these payment intents manually or automatically.','RELATION',NULL,NULL,0,1,NULL,NULL,NULL,'Stripe API','https://github.com/stripe/openapi/blob/master/openapi/spec3.json','stripe/openapi spec3','2026-06-14 20:18:12','2026-06-27 07:45:20');
