INSERT INTO "DataItems" VALUES(1770,1,'customer.customer_account','customer_account','The ID of an Account representing a customer. You can use this ID with any v1 API that accepts a customer_account parameter.','VARCHAR',5000,NULL,0,1,NULL,NULL,NULL,'Stripe API','https://github.com/stripe/openapi/blob/master/openapi/spec3.json','stripe/openapi spec3','2026-06-14 20:18:12','2026-06-27 07:45:20');
