INSERT INTO "DataItems" VALUES(1772,1,'customer.delinquent','delinquent','Tracks the most recent state change on any invoice belonging to the customer. Paying an invoice or marking it uncollectible via the API will set this field to false. An automatic payment failure or passing the `invoice.due_date` will set this field to `true`.
INSERT INTO "DataItems" VALUES(1773,1,'customer.description','description','An arbitrary string attached to the object. Often useful for displaying to users.','VARCHAR',5000,NULL,0,1,NULL,NULL,NULL,'Stripe API','https://github.com/stripe/openapi/blob/master/openapi/spec3.json','stripe/openapi spec3','2026-06-14 20:18:12','2026-06-27 07:45:20');
