INSERT INTO "DataItems" VALUES(1778,1,'customer.invoice_credit_balance','invoice_credit_balance','The current multi-currency balances, if any, that''s stored on the customer. If positive in a currency, the customer has a credit to apply to their next invoice denominated in that currency. If negative, the customer has an amount owed that''s added to their next invoice denominated in that currency. These balances don''t apply to unpaid invoices. They solely track amounts that Stripe hasn''t successfully applied to any invoice. Stripe only applies a balance in a specific currency to an invoice after that invoice (which is in the same currency) finalizes.','OBJECT',NULL,NULL,0,1,NULL,NULL,NULL,'Stripe API','https://github.com/stripe/openapi/blob/master/openapi/spec3.json','stripe/openapi spec3','2026-06-14 20:18:12','2026-06-27 07:45:20');
