INSERT INTO "DataItems" VALUES(1803,4,'product.object','object','String representing the object''s type. Objects of the same type share the same value.','VARCHAR',NULL,NULL,1,0,NULL,'["product"]',NULL,'Stripe API','https://github.com/stripe/openapi/blob/master/openapi/spec3.json','stripe/openapi spec3','2026-06-14 20:18:12','2026-06-27 07:45:20');
