INSERT INTO "DataItems" VALUES(1806,4,'product.statement_descriptor','statement_descriptor','Extra information about a product which will appear on your customer''s credit card statement. In the case that multiple products are billed at once, the first statement descriptor will be used. Only used for subscription payments.','VARCHAR',5000,NULL,0,1,NULL,NULL,NULL,'Stripe API','https://github.com/stripe/openapi/blob/master/openapi/spec3.json','stripe/openapi spec3','2026-06-14 20:18:12','2026-06-27 07:45:20');
