INSERT INTO "DataItems" VALUES(1808,4,'product.unit_label','unit_label','A label that represents units of this product. When set, this will be included in customers'' receipts, invoices, Checkout, and the customer portal.','VARCHAR',5000,NULL,0,1,NULL,NULL,NULL,'Stripe API','https://github.com/stripe/openapi/blob/master/openapi/spec3.json','stripe/openapi spec3','2026-06-14 20:18:12','2026-06-27 07:45:20');
INSERT INTO "DataItems" VALUES(1809,4,'product.updated','updated','Time at which the object was last updated. Measured in seconds since the Unix epoch.','INTEGER',NULL,NULL,1,0,NULL,NULL,NULL,'Stripe API','https://github.com/stripe/openapi/blob/master/openapi/spec3.json','stripe/openapi spec3','2026-06-14 20:18:12','2026-06-27 07:45:20');
