INSERT INTO "DataItems" VALUES(1963,3,'charge.refunded','refunded','Whether the charge has been fully refunded. If the charge is only partially refunded, this attribute will still be false.','BOOLEAN',NULL,NULL,1,0,NULL,NULL,NULL,'Stripe API','https://github.com/stripe/openapi/blob/master/openapi/spec3.json','stripe/openapi spec3','2026-06-14 20:18:12','2026-06-27 07:45:20');
INSERT INTO "DataItems" VALUES(1964,3,'charge.refunds','refunds','A list of refunds that have been applied to the charge.','OBJECT',NULL,NULL,0,1,NULL,NULL,NULL,'Stripe API','https://github.com/stripe/openapi/blob/master/openapi/spec3.json','stripe/openapi spec3','2026-06-14 20:18:12','2026-06-27 07:45:20');
