INSERT INTO "DataItems" VALUES(1967,3,'charge.source_transfer','source_transfer','The transfer ID which created this charge. Only present if the charge came from another Stripe account. [See the Connect documentation](https://docs.stripe.com/connect/destination-charges) for details.','VARCHAR',NULL,NULL,0,1,NULL,NULL,NULL,'Stripe API','https://github.com/stripe/openapi/blob/master/openapi/spec3.json','stripe/openapi spec3','2026-06-14 20:18:12','2026-06-27 07:45:20');
INSERT INTO "DataItems" VALUES(1968,3,'charge.statement_descriptor','statement_descriptor','For a non-card charge, text that appears on the customer''s statement as the statement descriptor. This value overrides the account''s default statement descriptor. For information about requirements, including the 22-character limit, see [the Statement Descriptor docs](https://docs.stripe.com/get-started/account/statement-descriptors).
INSERT INTO "DataItems" VALUES(1969,3,'charge.statement_descriptor_suffix','statement_descriptor_suffix','Provides information about a card charge. Concatenated to the account''s [statement descriptor prefix](https://docs.stripe.com/get-started/account/statement-descriptors#static) to form the complete statement descriptor that appears on the customer''s statement. If the account has no prefix value, the suffix is concatenated to the account''s statement descriptor.','VARCHAR',5000,NULL,0,1,NULL,NULL,NULL,'Stripe API','https://github.com/stripe/openapi/blob/master/openapi/spec3.json','stripe/openapi spec3','2026-06-14 20:18:12','2026-06-27 07:45:20');
INSERT INTO "DataItems" VALUES(1970,3,'charge.status','status','The status of the payment is either `succeeded`, `pending`, or `failed`.','VARCHAR',NULL,NULL,1,0,NULL,'["failed", "pending", "succeeded"]',NULL,'Stripe API','https://github.com/stripe/openapi/blob/master/openapi/spec3.json','stripe/openapi spec3','2026-06-14 20:18:12','2026-06-27 07:45:20');
