INSERT INTO "DataItems" VALUES(1972,3,'charge.transfer_data','transfer_data','An optional dictionary including the account to automatically transfer to as part of a destination charge. [See the Connect documentation](https://docs.stripe.com/connect/destination-charges) for details.','RELATION',NULL,NULL,0,1,NULL,NULL,NULL,'Stripe API','https://github.com/stripe/openapi/blob/master/openapi/spec3.json','stripe/openapi spec3','2026-06-14 20:18:12','2026-06-27 07:45:20');
INSERT INTO "DataItems" VALUES(1973,3,'charge.transfer_group','transfer_group','A string that identifies this transaction as part of a group. See the [Connect documentation](https://docs.stripe.com/connect/separate-charges-and-transfers#transfer-options) for details.','VARCHAR',5000,NULL,0,1,NULL,NULL,NULL,'Stripe API','https://github.com/stripe/openapi/blob/master/openapi/spec3.json','stripe/openapi spec3','2026-06-14 20:18:12','2026-06-27 07:45:20');
