INSERT INTO "DataItems" VALUES(1976,3,'payout.application_fee_amount','application_fee_amount','The amount of the application fee (if any) requested for the payout. [See the Connect documentation](https://docs.stripe.com/connect/instant-payouts#monetization-and-fees) for details.','INTEGER',NULL,NULL,0,1,NULL,NULL,NULL,'Stripe API','https://github.com/stripe/openapi/blob/master/openapi/spec3.json','stripe/openapi spec3','2026-06-14 20:18:12','2026-06-27 07:45:20');
