INSERT INTO "DataItems" VALUES(1999,3,'payout.trace_id','trace_id','A value that generates from the beneficiary''s bank that allows users to track payouts with their bank. Banks might call this a "reference number" or something similar.','RELATION',NULL,NULL,0,1,NULL,NULL,NULL,'Stripe API','https://github.com/stripe/openapi/blob/master/openapi/spec3.json','stripe/openapi spec3','2026-06-14 20:18:12','2026-06-27 07:45:20');
