INSERT INTO "DataItems" VALUES(2028,3,'payment_intent.application_fee_amount','application_fee_amount','The amount of the application fee (if any) that will be requested to be applied to the payment and transferred to the application owner''s Stripe account. The amount of the application fee collected will be capped at the total amount captured. For more information, see the PaymentIntents [use case for connected accounts](https://docs.stripe.com/payments/connected-accounts).','INTEGER',NULL,NULL,0,1,NULL,NULL,NULL,'Stripe API','https://github.com/stripe/openapi/blob/master/openapi/spec3.json','stripe/openapi spec3','2026-06-14 20:18:12','2026-06-27 07:45:20');
