INSERT INTO "DataItems" VALUES(2070,2,'quote.application_fee_amount','application_fee_amount','The amount of the application fee (if any) that will be requested to be applied to the payment and transferred to the application owner''s Stripe account. Only applicable if there are no line items with recurring prices on the quote.','INTEGER',NULL,NULL,0,1,NULL,NULL,NULL,'Stripe API','https://github.com/stripe/openapi/blob/master/openapi/spec3.json','stripe/openapi spec3','2026-06-14 20:18:12','2026-06-27 07:45:20');
INSERT INTO "DataItems" VALUES(2071,2,'quote.application_fee_percent','application_fee_percent','A non-negative decimal between 0 and 100, with at most two decimal places. This represents the percentage of the subscription invoice total that will be transferred to the application owner''s Stripe account. Only applicable if there are line items with recurring prices on the quote.','DECIMAL',NULL,NULL,0,1,NULL,NULL,NULL,'Stripe API','https://github.com/stripe/openapi/blob/master/openapi/spec3.json','stripe/openapi spec3','2026-06-14 20:18:12','2026-06-27 07:45:20');
INSERT INTO "DataItems" VALUES(2072,2,'quote.automatic_tax','automatic_tax','Automatic tax (Stripe Tax) status for the quote — whether tax is calculated automatically.','RELATION',NULL,NULL,1,0,NULL,NULL,NULL,'Stripe API','https://github.com/stripe/openapi/blob/master/openapi/spec3.json','stripe/openapi spec3','2026-06-14 20:18:12','2026-06-27 07:45:20');
INSERT INTO "DataItems" VALUES(2073,2,'quote.collection_method','collection_method','Either `charge_automatically`, or `send_invoice`. When charging automatically, Stripe will attempt to pay invoices at the end of the subscription cycle or on finalization using the default payment method attached to the subscription or customer. When sending an invoice, Stripe will email your customer an invoice with payment instructions and mark the subscription as `active`. Defaults to `charge_automatically`.','VARCHAR',NULL,NULL,1,0,NULL,'["charge_automatically", "send_invoice"]',NULL,'Stripe API','https://github.com/stripe/openapi/blob/master/openapi/spec3.json','stripe/openapi spec3','2026-06-14 20:18:12','2026-06-27 07:45:20');
