INSERT INTO "DataItems" VALUES(2078,2,'quote.customer_account','customer_account','The account representing the customer who received this quote. A customer or account is required to finalize the quote. Once specified, you can''t change it.','VARCHAR',5000,NULL,0,1,NULL,NULL,NULL,'Stripe API','https://github.com/stripe/openapi/blob/master/openapi/spec3.json','stripe/openapi spec3','2026-06-14 20:18:12','2026-06-27 07:45:20');
