INSERT INTO "DataItems" VALUES(2317,3,'invoice.broker','broker','An entity that arranges for an exchange between a buyer and a seller. In most cases a broker never acquires or releases ownership of a product or service involved in an exchange. If it is not clear whether an entity is a broker, seller, or buyer, the latter two terms are preferred. (references Organization, Person)','RELATION',NULL,NULL,0,1,NULL,NULL,NULL,'Schema.org','https://schema.org/broker','schemaorg-current-https','2026-06-14 20:18:12','2026-06-27 07:45:20');
