INSERT INTO "DataItems" VALUES(2370,1,'organization.founding_location','foundingLocation','The place where the Organization was founded. (references Place)','RELATION',NULL,NULL,0,1,NULL,NULL,NULL,'Schema.org','https://schema.org/foundingLocation','schemaorg-current-https','2026-06-14 20:18:12','2026-06-27 07:45:20');
