INSERT INTO "DataItems" VALUES(2376,1,'organization.has_gs1_digital_link','hasGS1DigitalLink','The GS1 digital link associated with the object. This URL should conform to the particular requirements of digital links. The link should only contain the Application Identifiers (AIs) that are relevant for the entity being annotated, for instance a [[Product]] or an [[Organization]], and for the correct granularity. In particular, for products:A Digital Link that contains a serial number (AI 21) should only be present on instances of [[IndividualProduct]]A Digital Link that contains a lot number (AI 10) should be annotated as [[SomeProducts]] if only products from that lot are sold, or [[IndividualProduct]] if there is only a specific product.A Digital Link that contains a global model number (AI 8013) should be attached to a [[Product]] or a [[ProductModel]]. Other item types should be adapted similarly.','VARCHAR',NULL,NULL,0,1,NULL,NULL,NULL,'Schema.org','https://schema.org/hasGS1DigitalLink','schemaorg-current-https','2026-06-14 20:18:12','2026-06-27 07:45:20');
