INSERT INTO "DataItems" VALUES(2395,1,'organization.main_entity_of_page','mainEntityOfPage','Indicates a page (or other CreativeWork) for which this thing is the main entity being described. See [background notes](/docs/datamodel.html#mainEntityBackground) for details.','VARCHAR',NULL,NULL,0,1,NULL,NULL,NULL,'Schema.org','https://schema.org/mainEntityOfPage','schemaorg-current-https','2026-06-14 20:18:12','2026-06-27 07:45:20');
