INSERT INTO "DataItems" VALUES(2399,1,'organization.members','members','A member of this organization. (references Organization, Person)','RELATION',NULL,NULL,0,1,NULL,NULL,NULL,'Schema.org','https://schema.org/members','schemaorg-current-https','2026-06-14 20:18:12','2026-06-27 07:45:20');
