INSERT INTO "DataItems" VALUES(2404,1,'organization.ownership_funding_info','ownershipFundingInfo','For an [[Organization]] (often but not necessarily a [[NewsMediaOrganization]]), a description of organizational ownership structure; funding and grants. In a news/media setting, this is with particular reference to editorial independence. Note that the [[funder]] is also available and can be used to make basic funder information machine-readable.','VARCHAR',NULL,NULL,0,1,NULL,NULL,NULL,'Schema.org','https://schema.org/ownershipFundingInfo','schemaorg-current-https','2026-06-14 20:18:12','2026-06-27 07:45:20');
INSERT INTO "DataItems" VALUES(2405,1,'organization.owns','owns','Things owned by the organization or person. (references Thing)','RELATION',NULL,NULL,0,1,NULL,NULL,NULL,'Schema.org','https://schema.org/owns','schemaorg-current-https','2026-06-14 20:18:12','2026-06-27 07:45:20');
