INSERT INTO "DataItems" VALUES(2414,1,'organization.skills','skills','A statement of knowledge, skill, ability, task or any other assertion expressing a competency that is either claimed by a person, an organization or desired or required to fulfill a role or to work in an occupation.','VARCHAR',NULL,NULL,0,1,NULL,NULL,NULL,'Schema.org','https://schema.org/skills','schemaorg-current-https','2026-06-14 20:18:12','2026-06-27 07:45:20');
