INSERT INTO "DataItems" VALUES(2428,11,'person.agent_interaction_statistic','agentInteractionStatistic','The number of completed interactions for this entity, in a particular role (the ''agent''), in a particular action (indicated in the statistic), and in a particular context (i.e. interactionService). (references InteractionCounter)','RELATION',NULL,NULL,0,1,NULL,NULL,NULL,'Schema.org','https://schema.org/agentInteractionStatistic','schemaorg-current-https','2026-06-14 20:18:12','2026-06-27 07:45:20');
