INSERT INTO "DataItems" VALUES(2464,11,'person.identifier','identifier','The identifier property represents any kind of identifier for any kind of [[Thing]], such as ISBNs, GTIN codes, UUIDs etc. Schema.org provides dedicated properties for representing many of these, either as textual strings or as URL (URI) links. See [background notes](/docs/datamodel.html#identifierBg) for more details.','VARCHAR',NULL,NULL,0,1,NULL,NULL,NULL,'Schema.org','https://schema.org/identifier','schemaorg-current-https','2026-06-14 20:18:12','2026-06-27 07:45:20');
INSERT INTO "DataItems" VALUES(2465,11,'person.image','image','An image of the item. This can be a [[URL]] or a fully described [[ImageObject]].','VARCHAR',NULL,NULL,0,1,NULL,NULL,NULL,'Schema.org','https://schema.org/image','schemaorg-current-https','2026-06-14 20:18:12','2026-06-27 07:45:20');
