INSERT INTO "DataItems" VALUES(2467,11,'person.isic_v4','isicV4','The International Standard of Industrial Classification of All Economic Activities (ISIC), Revision 4 code for a particular organization, business person, or place.','VARCHAR',NULL,NULL,0,1,NULL,NULL,NULL,'Schema.org','https://schema.org/isicV4','schemaorg-current-https','2026-06-14 20:18:12','2026-06-27 07:45:20');
