INSERT INTO "DataItems" VALUES(2469,11,'person.knows','knows','The most generic bi-directional social/work relation. (references Person)','RELATION',NULL,NULL,0,1,NULL,NULL,NULL,'Schema.org','https://schema.org/knows','schemaorg-current-https','2026-06-14 20:18:12','2026-06-27 07:45:20');
INSERT INTO "DataItems" VALUES(2470,11,'person.knows_about','knowsAbout','Of a [[Person]], and less typically of an [[Organization]], to indicate a topic that is known about - suggesting possible expertise but not implying it. We do not distinguish skill levels here, or relate this to educational content, events, objectives or [[JobPosting]] descriptions.','VARCHAR',NULL,NULL,0,1,NULL,NULL,NULL,'Schema.org','https://schema.org/knowsAbout','schemaorg-current-https','2026-06-14 20:18:12','2026-06-27 07:45:20');
INSERT INTO "DataItems" VALUES(2471,11,'person.knows_language','knowsLanguage','Of a [[Person]], and less typically of an [[Organization]], to indicate a known language. We do not distinguish skill levels or reading/writing/speaking/signing here. Use language codes from the [IETF BCP 47 standard](http://tools.ietf.org/html/bcp47).','VARCHAR',NULL,NULL,0,1,NULL,NULL,NULL,'Schema.org','https://schema.org/knowsLanguage','schemaorg-current-https','2026-06-14 20:18:12','2026-06-27 07:45:20');
INSERT INTO "DataItems" VALUES(2472,11,'person.life_event','lifeEvent','A life event like baptism, communions, Bar Mitzvahs, Aqiqah, Namakarana, Miyamairi, burial, .... (references Event)','RELATION',NULL,NULL,0,1,NULL,NULL,NULL,'Schema.org','https://schema.org/lifeEvent','schemaorg-current-https','2026-06-14 20:18:12','2026-06-27 07:45:20');
INSERT INTO "DataItems" VALUES(2473,11,'person.main_entity_of_page','mainEntityOfPage','Indicates a page (or other CreativeWork) for which this thing is the main entity being described. See [background notes](/docs/datamodel.html#mainEntityBackground) for details.','VARCHAR',NULL,NULL,0,1,NULL,NULL,NULL,'Schema.org','https://schema.org/mainEntityOfPage','schemaorg-current-https','2026-06-14 20:18:12','2026-06-27 07:45:20');
