INSERT INTO "DataItems" VALUES(2475,11,'person.member_of','memberOf','An Organization (or ProgramMembership) to which this Person or Organization belongs. (references MemberProgramTier, Organization, ProgramMembership)','RELATION',NULL,NULL,0,1,NULL,NULL,NULL,'Schema.org','https://schema.org/memberOf','schemaorg-current-https','2026-06-14 20:18:12','2026-06-27 07:45:20');
INSERT INTO "DataItems" VALUES(2476,11,'person.naics','naics','The North American Industry Classification System (NAICS) code for a particular organization or business person.','VARCHAR',NULL,NULL,0,1,NULL,NULL,NULL,'Schema.org','https://schema.org/naics','schemaorg-current-https','2026-06-14 20:18:12','2026-06-27 07:45:20');
