INSERT INTO "DataItems" VALUES(2485,11,'person.potential_action','potentialAction','Indicates a potential Action, which describes an idealized action in which this thing would play an ''object'' role. (references Action)','RELATION',NULL,NULL,0,1,NULL,NULL,NULL,'Schema.org','https://schema.org/potentialAction','schemaorg-current-https','2026-06-14 20:18:12','2026-06-27 07:45:20');
INSERT INTO "DataItems" VALUES(2486,11,'person.pronouns','pronouns','A short string listing or describing pronouns for a person. Typically the person concerned is the best authority as pronouns are a critical part of personal identity and expression. Publishers and consumers of this information are reminded to treat this data responsibly, take country-specific laws related to gender expression into account, and be wary of out-of-date data and drawing unwarranted inferences about the person being described. In English, formulations such as "they/them", "she/her", and "he/him" are commonly used online and can also be used here. We do not intend to enumerate all possible micro-syntaxes in all languages. More structured and well-defined external values for pronouns can be referenced using the [[StructuredValue]] or [[DefinedTerm]] values.','VARCHAR',NULL,NULL,0,1,NULL,NULL,NULL,'Schema.org','https://schema.org/pronouns','schemaorg-current-https','2026-06-14 20:18:12','2026-06-27 07:45:20');
INSERT INTO "DataItems" VALUES(2487,11,'person.publishing_principles','publishingPrinciples','The publishingPrinciples property indicates (typically via [[URL]]) a document describing the editorial principles of an [[Organization]] (or individual, e.g. a [[Person]] writing a blog) that relate to their activities as a publisher, e.g. ethics or diversity policies. When applied to a [[CreativeWork]] (e.g. [[NewsArticle]]) the principles are those of the party primarily responsible for the creation of the [[CreativeWork]]. While such policies are most typically expressed in natural language, sometimes related information (e.g. indicating a [[funder]]) can be expressed using schema.org terminology.','VARCHAR',NULL,NULL,0,1,NULL,NULL,NULL,'Schema.org','https://schema.org/publishingPrinciples','schemaorg-current-https','2026-06-14 20:18:12','2026-06-27 07:45:20');
INSERT INTO "DataItems" VALUES(2488,11,'person.related_to','relatedTo','The most generic familial relation. (references Person)','RELATION',NULL,NULL,0,1,NULL,NULL,NULL,'Schema.org','https://schema.org/relatedTo','schemaorg-current-https','2026-06-14 20:18:12','2026-06-27 07:45:20');
